import React, { useState } from 'react'
import Head from 'next/head'
import Link from 'next/link'
import fetch from 'isomorphic-unfetch'

const Home = ({ data }) => {
  // const week = Object.values(data[`week-1`])
  const week = {
    "monday": {
      "label":"Mon",
      "exercise":"Rest",
      "tag":"rest"
    },
    "tuesday": {
      "label":"Tue",
      "exercise":"3 mi run",
      "tag":"run"
    },
    "wednesday": {
      "label":"Wed",
      "exercise":"2 mi run or cross",
      "tag":"crossrun"
    },
    "thursday": {
      "label":"Thu",
      "exercise":"3 mi run",
      "tag":"run"
    },
    "friday": {
      "label":"Fri",
      "exercise":"Rest",
      "tag":"rest"
    },
    "saturday": {
      "label":"Sat",
      "exercise":"30 min cross",
      "tag":"cross"
    },
    "sunday": {
      "label":"Sun",
      "exercise":"4 mi run",
      "tag":"run"
    }
  }

  return(
    <div className="container">

      <Head>
        <title>Week 1</title>
        <link rel="icon" href="" />
      </Head>

      <div className="week-header">
        <h1>Week 1</h1>
      </div>


      <div className="exercise-grid">
      {
       Object.values(week).map((foo, i) => (
         <div key={i} className="details-container">

            <div className="tag-guide">
              {
                foo.tag === 'rest' ? 
                  <div className="tag-dot rest"></div> : 
                foo.tag === 'run' ? 
                  <div className="tag-dot run"></div> :
                foo.tag === 'cross' ? 
                  <div className="tag-dot cross"></div> :
                foo.tag === 'crossrun' ? 
                  <div className="tag-dot crossrun"></div> :
                  <div className="tag-dot other"></div>
              }
              <div className="tag-line"></div>
            </div>

            <div className="day-exercise">
              <h1>{foo.label}</h1>
              <p>{foo.exercise}</p>
            </div>
          </div>
        ))
      }
      </div>

      <style jsx>{`
        .container{
          height: 100%;
          width: 100%;
          padding-top: 5rem;
          display: flex;
          flex-flow: column;
          justify-content: center;
          align-items: center;
          font-family: sans-serif;
        }

        .week-header{
          font-size: 4rem;
          margin: 0;
          padding: 0;
          display: grid;
          grid-template-columns: 1fr .7fr;
        }

        .week-header h1{
          place-self: center ce;
          height: 100%;
          width: 100%;
          margin: 0;
          padding: 0;
        }

        .exercise-grid{
          display: grid;
          grid-template-rows: repeat(7, 14.25%);
          width: 50%;
        }

        .details-container{
          display: grid;
          grid-template-columns: 1fr 1fr;
          margin-bottom: 3rem;
        }

        .tag-guide{
          display: grid;
          grid-template-rows: 25% 130%;
        }

        .tag-line{
          height: 100%;
          width: 1px;
          background-color: black;
          place-self: end;
          margin-right: .3rem;
        }


        .day-exercise{
          margin-left: 5rem;
          align-self: center;
        }

        .day-exercise h1{
          margin: 0;
          font-size: 2rem;
          line-height: 10px;
        }


        .tag-dot{
          align-self: start;
          justify-self: end;
          height: 10px;
          width: 10px;
          border-radius: 100px;
        }
        .rest{
          background-color: cyan;
        }
        .run{
          background-color: red;
        }
        .cross{
          background-color: yellow;
        }
        .crossrun{
          background-color: orange;
        }
        .other{
          background-color: black;
        }

      `}
      </style>

    </div>
  )
}

// Home.getInitialProps = async () => {
//   const res = await fetch('http://localhost:3000/api/daily')
//   const json = await res.json()

//   return { data: json }
// }

export default Home
